from sys import stdin, stdout

s = stdin.readline().strip()

n = len(s)

def solve(s):
    i = 0
    j = 0
    while i < n and j < n:
        if s[i] == s[j]:
            i += 1
            j += 1
        else:
            i = j
            j += 1
    return i

