    while i < n and j < n:
        if s[i] == s[j]:
            i += 1
            j += 1
        else:
            i += 1
            j += 1
    return i

def solve3(s):
    i = 0
    j = 0
    while i < n and j < n:
        if s[i] == s[j]:
            i += 1
            j += 1
        else:
            i += 1
            j += 2
    return i

i = solve(s)
j = solve2(s)
k = solve3(s)

if i > j and i > k:
    stdout.write(s[:i])
elif j > i and j > k:
    stdout.write(s[:j])
else:
    stdout.write(s[:k])
